// In rendering (pseudocode)
fn render_span(span: &Span, area: Rect, buf: &mut Buffer) {
    if let Some(bidi) = &span.bidi {
        for (visual_col, &logical_idx) in bidi.visual_to_logical.iter().enumerate() {
            let ch = bidi.chars[logical_idx];
            buf.set_char(area.x + visual_col as u16, area.y, ch);
        }
    } else {
        // Simple LTR rendering
    }
}
